/* ── Twinkling star ── */
function Star({ pos, color, size = 0.055 }) {
  const ref = useRef();
  const phase = useRef(Math.random() * Math.PI * 2);
  useFrame(({ clock }) => {
    if (!ref.current) return;
    const t = 0.7 + Math.sin(clock.elapsedTime * 1.5 + phase.current) * 0.3;
    ref.current.material.opacity = t;
  });
  return (
    <mesh ref={ref} position={pos}>
      <sphereGeometry args={[size, 8, 8]} />
      <meshBasicMaterial color={color} transparent opacity={0.9} />
    </mesh>
  );
}

/* ── Constellation line ── */
function ConstellationLine({ p1, p2, color }) {
  const obj = useMemo(() => {
    const geo = new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(...p1),
      new THREE.Vector3(...p2),
    ]);
    const mat = new THREE.LineBasicMaterial({ color, transparent: true, opacity: 0.3 });
    return new THREE.Line(geo, mat);
  }, [p1, p2, color]);
  return <primitive object={obj} />;
}

/* ── Ambient star background ── */
function BgStars() {
  const geo = useMemo(() => {
    const COUNT = 400;
    const pos = new Float32Array(COUNT * 3);
    for (let i = 0; i < COUNT; i++) {
      pos[i * 3]     = (Math.random() - 0.5) * 14;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 9;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 5 - 2;
    }
    const g = new THREE.BufferGeometry();
    g.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    return g;
  }, []);
  return (
    <points geometry={geo}>
      <pointsMaterial color="#C49A7A" size={0.012} transparent opacity={0.18} sizeAttenuation />
    </points>
  );
}

/* ── Scene ── */
function ConstellationScene() {
  const groupRef = useRef();
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    const t = clock.elapsedTime;
    groupRef.current.rotation.y = t * 0.06;
    groupRef.current.rotation.x = Math.sin(t * 0.08) * 0.08;
  });

  return (
    <group ref={groupRef}>
      <BgStars />
      {CONSTELLATIONS.map((c, ci) =>
        c.lines.map(([a, b], li) => (
          <ConstellationLine
            key={`${ci}-${li}`}
            p1={c.stars[a].pos}
            p2={c.stars[b].pos}
            color={c.color}
          />
        ))
      )}
      {CONSTELLATIONS.map((c) =>
        c.stars.map((s, si) => (
          <Star key={`${c.name}-${si}`} pos={s.pos} color={c.color} />
        ))
      )}
    </group>
  );
}

